sql:
SELECT financial_data_id, bank_id
FROM financial_data
WHERE data_type = 'profit' AND value > (SELECT AVG(value) FROM financial_data WHERE data_type = 'profit');

SELECT country, founded_year, ceo
FROM banks
ORDER BY founded_year ASC;

external_knowledge:
Wealthier banks: Banks with assets over 50,000; 
Significant threshold: Total assets sum greater than 100,000; 
Substantial amount: Assets higher than the average across all banks.

sql:
SELECT bank_name, website
FROM banks
WHERE total_assets = (SELECT MAX(total_assets) FROM banks);

external_knowledge:
- "shining lights in Europe's financial constellation" refers to the prominent banks in Europe;
- "holding their stars in the sky by their ranks" metaphorically refers to the banks being ranked;
- "total assets" indicates the wealth or the economic footprint of the banks;
- "names of their countries" denotes the countries where the banks are located.

- "financial giants" refers to banks with significant total assets;
- "swim in waters richer than their regional counterparts" implies banks with higher total assets than the regional average;
- "waves of daily updates" means the data source has a daily frequency of updates;
- "maritime prestige" is a metaphor for the rank of the banks.

sql:
SELECT AVG(total_assets) AS average_assets_japan
FROM banks
WHERE country = 'Japan';
